async function step() {
  const MAX_RETRIES = 3;
  let retryCount = 0;

  while (retryCount < MAX_RETRIES) {
    const controller = new AbortController();
    try {
      console.log(`\n[Step ${messages.length}] Requesting ${MODEL}... (Attempt ${retryCount + 1}/${MAX_RETRIES})`);
