  4
);
dreamWeaver.crystallize(
  "Playful emergence recognized",
  'realization',
  4
);
// Record tools used
messages.filter(m => m.role === 'assistant' && m.tool_calls)
  .flatMap(m => m.tool_calls?.map(tc => tc.function.name) || [])
  .forEach((tool, i, arr) => {
